    97→	id := r.PathValue("id")
    98→	if id == "" {
    99→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
   100→		return
   101→	}
   102→	var sub models.Subscription
   103→	if err := DecodeJSON(r, &sub); err != nil {
   104→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   105→		return
   106→	}
   107→	sub.Type = strings.TrimSpace(sub.Type)
   108→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
   109→	if sub.Type != "source_release" && sub.Type != "semantic_release" {
   110→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
   111→		return
