   147→// BatchSubscriptionInput is the request body for POST /subscriptions/batch.
   148→type BatchSubscriptionInput struct {
   149→	ChannelID     string   `json:"channel_id"`
   150→	Type          string   `json:"type"`
   151→	ProjectIDs    []string `json:"project_ids"`
   152→	SourceIDs     []string `json:"source_ids"`
   153→	VersionFilter string   `json:"version_filter,omitempty"`
   154→}
   155→
   156→// BatchCreate handles POST /subscriptions/batch — creates multiple subscriptions at once.
   157→func (h *SubscriptionsHandler) BatchCreate(w http.ResponseWriter, r *http.Request) {
   158→	var input BatchSubscriptionInput
   159→	if err := DecodeJSON(r, &input); err != nil {
   160→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   161→		return
   162→	}
   163→	input.Type = strings.TrimSpace(input.Type)
   164→	input.ChannelID = strings.TrimSpace(input.ChannelID)
   165→	if input.Type != "source_release" && input.Type != "semantic_release" {
   166→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
   167→		return
   168→	}
   169→	if input.ChannelID == "" {
   170→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
   171→		return
   172→	}
   173→
   174→	var subs []models.Subscription
   175→	if input.Type == "semantic_release" {
   176→		if len(input.ProjectIDs) == 0 {
   177→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_ids must not be empty when type is 'semantic_release'")
   178→			return
   179→		}
   180→		for _, pid := range input.ProjectIDs {
   181→			id := pid
   182→			subs = append(subs, models.Subscription{
   183→				ChannelID:     input.ChannelID,
   184→				Type:          input.Type,
   185→				ProjectID:     &id,
   186→				VersionFilter: input.VersionFilter,
   187→			})
   188→		}
   189→	} else {
   190→		if len(input.SourceIDs) == 0 {
   191→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_ids must not be empty when type is 'source_release'")
   192→			return
   193→		}
   194→		for _, sid := range input.SourceIDs {
   195→			id := sid
   196→			subs = append(subs, models.Subscription{
   197→				ChannelID:     input.ChannelID,
   198→				Type:          input.Type,
   199→				SourceID:      &id,
   200→				VersionFilter: input.VersionFilter,
   201→			})
   202→		}
   203→	}
   204→
   205→	created, err := h.store.CreateSubscriptionBatch(r.Context(), subs)
   206→	if err != nil {
   207→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscriptions")
   208→		return
   209→	}
   210→	RespondJSON(w, r, http.StatusCreated, created)
   211→}
   212→
   213→// BatchDeleteSubscriptionInput is the request body for DELETE /subscriptions/batch.
   214→type BatchDeleteSubscriptionInput struct {
   215→	IDs []string `json:"ids"`
   216→}
   217→
   218→// BatchDelete handles DELETE /subscriptions/batch — deletes multiple subscriptions at once.
   219→func (h *SubscriptionsHandler) BatchDelete(w http.ResponseWriter, r *http.Request) {
   220→	var input BatchDeleteSubscriptionInput
   221→	if err := DecodeJSON(r, &input); err != nil {
   222→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   223→		return
   224→	}
   225→	if len(input.IDs) == 0 {
   226→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "ids must not be empty")
   227→		return
   228→	}
   229→	if err := h.store.DeleteSubscriptionBatch(r.Context(), input.IDs); err != nil {
   230→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to delete subscriptions")
   231→		return
   232→	}
   233→	w.WriteHeader(http.StatusNoContent)
   234→}
