   138→	}
   139→	w.WriteHeader(http.StatusNoContent)
   140→}
   141→
   142→// FetchReleases handles POST /sources/{id}/releases — polls upstream for new
   143→// releases and ingests them immediately.
   144→func (h *SourcesHandler) FetchReleases(w http.ResponseWriter, r *http.Request) {
   145→	id := r.PathValue("id")
   146→	if id == "" {
   147→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   148→		return
   149→	}
   150→	src, err := h.store.GetSource(r.Context(), id)
   151→	if err != nil {
   152→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   153→		return
   154→	}
   155→
   156→	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   157→	if ingestionSrc == nil {
   158→		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   159→		return
   160→	}
   161→
   162→	results, err := ingestionSrc.FetchNewReleases(r.Context())
   163→	if err != nil {
   164→		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   165→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   166→		return
   167→	}
   168→
   169→	newCount := 0
   170→	if len(results) > 0 && h.ingestionService != nil {
   171→		for _, result := range results {
   172→			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   173→				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
   174→				continue
   175→			}
   176→			newCount++
   177→		}
   178→	}
   179→
   180→	RespondJSON(w, r, http.StatusOK, map[string]int{"new_releases": newCount})
   181→}
