   344→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   345→	tx, err := s.pool.Begin(ctx)
   346→	if err != nil {
   347→		return nil, fmt.Errorf("begin tx: %w", err)
   348→	}
   349→	defer tx.Rollback(ctx)
   350→
   351→	var result []models.Subscription
   352→	for i := range subs {
   353→		sub := subs[i]
   354→		err := tx.QueryRow(ctx,
   355→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   356→			 VALUES ($1, $2, $3, $4, $5)
   357→			 RETURNING id, created_at`,
   358→			sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   359→		).Scan(&sub.ID, &sub.CreatedAt)
   360→		if err != nil {
   361→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   362→		}
   363→		result = append(result, sub)
   364→	}
   365→
   366→	if err := tx.Commit(ctx); err != nil {
   367→		return nil, fmt.Errorf("commit tx: %w", err)
   368→	}
   369→	return result, nil
   370→}
