   779→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   780→		 VALUES ($1, $2, $3, 'pending')
   781→		 RETURNING id`, projectID, trigger, version,
   782→	).Scan(&runID)
   783→	if err != nil {
   784→		return fmt.Errorf("insert agent run: %w", err)
