   789→			AgentRunID: runID,
   790→			ProjectID:  projectID,
   791→			Version:    version,
   792→		}, nil)
   793→		if err != nil {
   794→			return fmt.Errorf("enqueue agent job: %w", err)
   795→		}
   796→	}
