   948→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   949→	// Validate granularity to one of three literal values (no injection risk).
   950→	var trunc string
   951→	switch granularity {
   952→	case "daily":
   953→		trunc = "day"
   954→	case "weekly":
   955→		trunc = "week"
   956→	case "monthly":
   957→		trunc = "month"
   958→	default:
   959→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   960→	}
   961→
   962→	query := fmt.Sprintf(`
   963→		WITH buckets AS (
   964→			SELECT date_trunc('%s', gs)::date AS period
   965→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   966→		)
   967→		SELECT
   968→			b.period,
   969→			COALESCE(r.cnt, 0) AS releases,
   970→			COALESCE(sr.cnt, 0) AS semantic_releases
   971→		FROM buckets b
   972→		LEFT JOIN (
   973→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   974→			       COUNT(*) AS cnt
   975→			FROM releases
   976→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   977→			GROUP BY 1
   978→		) r ON r.period = b.period
   979→		LEFT JOIN (
   980→			SELECT date_trunc('%s', created_at)::date AS period,
   981→			       COUNT(*) AS cnt
   982→			FROM semantic_releases
   983→			WHERE created_at >= $1 AND created_at < $2
   984→			GROUP BY 1
   985→		) sr ON sr.period = b.period
   986→		ORDER BY b.period
   987→	`, trunc, trunc, trunc, trunc)
   988→
   989→	rows, err := s.pool.Query(ctx, query, start, end)
   990→	if err != nil {
   991→		return nil, fmt.Errorf("get trend: %w", err)
   992→	}
   993→	defer rows.Close()
   994→
   995→	var buckets []TrendBucket
   996→	for rows.Next() {
   997→		var b TrendBucket
   998→		var period time.Time
   999→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
  1000→			return nil, fmt.Errorf("scan trend bucket: %w", err)
  1001→		}
  1002→		b.Period = period.Format("2006-01-02")
  1003→		buckets = append(buckets, b)
  1004→	}
  1005→	if buckets == nil {
  1006→		buckets = []TrendBucket{}
  1007→	}
  1008→	return buckets, nil
  1009→}
